import React, { useState, useEffect } from 'react';
import './Settings.css';

function Settings() {
  const [domain, setDomain] = useState('');
  const [jiraUsername, setJiraUsername] = useState('');
  const [jiraApiToken, setJiraApiToken] = useState('');
  const [locked, setLocked] = useState(true);
  const [credentials, setCredentials] = useState([]);
  const [checkedCredentials, setCheckedCredentials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Fetch stored credentials from the backend
  const fetchCredentials = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('https://localhost:7216/api/Auth/credentials');
      if (!response.ok) {
        throw new Error('Failed to fetch credentials');
      }
      const data = await response.json();
      setCredentials(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCredentials();
  }, []);

  const handleLockToggle = () => {
    setLocked(!locked);
  };

  const handleDelete = async (id) => {
    try {
      const response = await fetch(`https://localhost:7216/api/settings/delete/${id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        setCredentials(credentials.filter((cred) => cred.id !== id));
      } else {
        throw new Error('Failed to delete credential');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  const handleCheckboxChange = (id) => {
    if (checkedCredentials.includes(id)) {
      setCheckedCredentials(checkedCredentials.filter((checkboxId) => checkboxId !== id));
    } else {
      setCheckedCredentials([...checkedCredentials, id]);
    }
  };

  const handleSave = async () => {
    try {
      const payload = { domain, jiraUsername, jiraApiToken };
      const response = await fetch('https://localhost:7216/api/settings/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        fetchCredentials(); // Refresh the credentials after saving
      } else {
        throw new Error('Failed to save credentials');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>
      {error && <div className="error">{error}</div>}

      <div className="credentials-form">
        <div className="field">
          <label>Domain</label>
          <input
            type="text"
            value={domain}
            onChange={(e) => setDomain(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira Username</label>
          <input
            type="text"
            value={jiraUsername}
            onChange={(e) => setJiraUsername(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira API Token</label>
          <input
            type="password"
            value={jiraApiToken}
            onChange={(e) => setJiraApiToken(e.target.value)}
            disabled={locked}
          />
        </div>

        <button className="save-button" onClick={handleSave} disabled={locked}>Save</button>
        <button className="lock-button" onClick={handleLockToggle}>
          {locked ? 'Unlock Fields' : 'Lock Fields'}
        </button>
      </div>

      <div className="credentials-list">
        <h3>Stored Credentials</h3>
        {loading ? (
          <div>Loading...</div>
        ) : (
          <div className="credentials-items">
            {credentials.map((cred) => (
              <div key={cred.id} className="credential-item">
                <input
                  type="checkbox"
                  onChange={() => handleCheckboxChange(cred.id)}
                />
                <div className="credential-info">
                  <p><strong>Domain:</strong> {cred.domain}</p>
                  <p><strong>Username:</strong> {cred.jiraUsername}</p>
                  <button
                    className="delete-button"
                    onClick={() => handleDelete(cred.id)}
                    disabled={!checkedCredentials.includes(cred.id)}
                  >
                    Delete
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default Settings;
